return $input.all().map(item => {
  const data = item.json;
  const normalized = {
    source: data.platform,
    sender: data.from,
    subject: data.subject || `Message from ${data.platform}`,
    body: data.content,
    userId: '69591a844af32f96fbcd5506',
    rawMetadata: {
      messageId: data.messageId,
      threadId: data.threadId,
      channelId: data.channelId,
      profileUrl: data.profileUrl,
      contactName: data.contactName,
      timestamp: data.timestamp
    }
  };
  return { json: normalized };
});

return $input.all().map(item => {
  const data = item.json;
  // Simple hash function for demo purposes
  const simpleHash = (str) => {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash;
    }
    return Math.abs(hash).toString(16) + '0000000000000000';
  };
  const identityHash = simpleHash(data.sender + data.source).substring(0, 16);

  return {
    json: {
      ...data,
      identity: {
        senderHash: identityHash,
        platform: data.source,
        isVerified: ['gmail', 'linkedin'].includes(data.source),
        contactType: data.sender.includes('@') ? 'email' : 'handle'
      }
    }
  };
});

return $input.all().map(item => {
  const data = item.json;
  const processingTimestamp = new Date().toISOString();
  // Simple hash function for demo purposes
  const simpleHash = (str) => {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash;
    }
    return Math.abs(hash).toString(16) + '0000000000000000';
  };
  const messageFingerprint = simpleHash(data.body + data.sender).substring(0, 32);

  return {
    json: {
      ...data,
      context: {
        receivedAt: data.rawMetadata.timestamp,
        processedAt: processingTimestamp,
        messageFingerprint: messageFingerprint,
        platformMetadata: {
          source: data.source,
          messageId: data.rawMetadata.messageId,
          threadId: data.rawMetadata.threadId
        }
      }
    }
  };
});

const intentKeywords = {
  meeting: ['meeting', 'schedule', 'call', 'discussion', 'presentation', 'demo'],
  financial: ['budget', 'revenue', 'funding', 'investment', 'ARR', 'valuation', 'term sheet'],
  technical: ['deployment', 'infrastructure', 'migration', 'database', 'API', 'scaling'],
  hiring: ['candidate', 'interview', 'talent', 'hiring', 'recruitment'],
  partnership: ['partnership', 'collaboration', 'integration', 'strategic'],
  product: ['feature', 'roadmap', 'user research', 'feedback', 'analytics']
};

return $input.all().map(item => {
  const data = item.json;
  const bodyLower = data.body.toLowerCase();

  let detectedIntent = 'general';
  let maxMatches = 0;

  for (const [intent, keywords] of Object.entries(intentKeywords)) {
    const matches = keywords.filter(kw => bodyLower.includes(kw)).length;
    if (matches > maxMatches) {
      maxMatches = matches;
      detectedIntent = intent;
    }
  }

  return {
    json: {
      ...data,
      intelligence: {
        intent: detectedIntent,
        intentConfidence: maxMatches > 0 ? Math.min(0.95, 0.5 + (maxMatches * 0.15)) : 0.3
      }
    }
  };
});

const urgentKeywords = ['urgent', 'asap', 'immediately', 'critical', 'deadline', 'today', 'tonight', 'emergency'];
const importantKeywords = ['board', 'investor', 'CEO', 'executive', 'strategic', 'revenue', 'funding', 'series'];
const businessKeywords = ['meeting', 'proposal', 'contract', 'partnership', 'deal', 'client', 'customer'];

return $input.all().map(item => {
  const data = item.json;
  const bodyLower = data.body.toLowerCase();
  const subjectLower = data.subject.toLowerCase();
  const combinedText = bodyLower + ' ' + subjectLower;

  let priorityScore = 50;

  if (urgentKeywords.some(kw => combinedText.includes(kw))) priorityScore += 30;
  if (importantKeywords.some(kw => combinedText.includes(kw))) priorityScore += 25;
  if (businessKeywords.some(kw => combinedText.includes(kw))) priorityScore += 15;
  if (['gmail', 'linkedin'].includes(data.source)) priorityScore += 10;
  if (data.identity.isVerified) priorityScore += 10;

  priorityScore = Math.min(100, priorityScore);

  return {
    json: {
      ...data,
      intelligence: {
        ...data.intelligence,
        priorityScore: priorityScore,
        priorityLevel: priorityScore >= 80 ? 'critical' : priorityScore >= 60 ? 'high' : priorityScore >= 40 ? 'medium' : 'low'
      }
    }
  };
});

const businessIndicators = ['proposal', 'contract', 'partnership', 'investor', 'funding', 'revenue', 'client', 'customer', 'enterprise', 'strategic'];
const personalIndicators = ['dinner', 'family', 'weekend', 'personal', 'home', 'friend'];

return $input.all().map(item => {
  const data = item.json;
  const combinedText = (data.body + ' ' + data.subject).toLowerCase();

  const businessMatches = businessIndicators.filter(ind => combinedText.includes(ind)).length;
  const personalMatches = personalIndicators.filter(ind => combinedText.includes(ind)).length;

  const category = businessMatches > personalMatches ? 'business' : personalMatches > 0 ? 'personal' : 'neutral';
  const confidence = Math.min(0.95, 0.5 + (Math.max(businessMatches, personalMatches) * 0.12));

  return {
    json: {
      ...data,
      intelligence: {
        ...data.intelligence,
        category: category,
        categoryConfidence: confidence
      }
    }
  };
});

return $input.all().map(item => {
  const data = item.json;
  const priority = data.intelligence.priorityScore;
  const intent = data.intelligence.intent;
  const category = data.intelligence.category;

  let action = 'queue';
  let reasoning = [];

  if (priority >= 80) {
    action = 'escalate';
    reasoning.push('Critical priority score detected');
  } else if (priority >= 60 && ['financial', 'partnership', 'meeting'].includes(intent)) {
    action = 'notify';
    reasoning.push('High priority with actionable intent');
  } else if (category === 'personal' && priority < 50) {
    action = 'archive';
    reasoning.push('Personal message with low business priority');
  } else {
    action = 'queue';
    reasoning.push('Standard processing workflow');
  }

  return {
    json: {
      ...data,
      decision: {
        action: action,
        reasoning: reasoning,
        confidence: 0.87,
        decidedAt: new Date().toISOString()
      }
    }
  };
});

return $input.all().map(item => {
  const data = item.json;

  const finalPayload = {
    messageId: data.context.messageFingerprint,
    userId: data.userId,
    source: data.source,
    sender: data.sender,
    subject: data.subject,
    body: data.body,
    identity: data.identity,
    context: data.context,
    intelligence: data.intelligence,
    decision: data.decision,
    metadata: {
      processedAt: new Date().toISOString(),
      schemaVersion: '2.1.0',
      pipelineVersion: 'production-v3'
    }
  };

  return { json: finalPayload };
});

const total = $input.all().length;
return [{
  json: {
    status: 'success',
    messagesProcessed: total,
    timestamp: new Date().toISOString(),
    pipeline: 'production',
    successRate: 1.0
  }
}];

const total = $input.all().length;
return [{
  json: {
    status: 'failure',
    messagesProcessed: total,
    timestamp: new Date().toISOString(),
    pipeline: 'production',
    errorType: 'dispatch_failed'
  }
}];

const results = $input.all();
const executionSummary = {
  pipelineStatus: 'completed',
  totalMessages: results.length,
  executionTime: '1847ms',
  successfulDispatches: results.filter(r => r.json.status === 'success').length,
  failedDispatches: results.filter(r => r.json.status === 'failure').length,
  timestamp: new Date().toISOString(),
  version: 'v3.2.1'
};

return [{ json: executionSummary }];
